const onscroll=(s,e)=>{s.addEventListener("scroll",e)};let navbarlinks=select("#navbar .scrollto",!0);const navbarlinksActive=()=>{let s=window.scrollY+200;navbarlinks.forEach(e=>{if(!e.hash)return;let t=select(e.hash);t&&(s>=t.offsetTop&&s<=t.offsetTop+t.offsetHeight?e.classList.add("active"):e.classList.remove("active"))})};window.addEventListener("load",navbarlinksActive),onscroll(document,navbarlinksActive);